SELECT HOMEPAGE_ID,TERMS_IDX, TERMS_TYPE, TITLE, CONTENTS, USE_YN, DELETE_YN, ADD_ID, ADD_DATE, MODIFY_ID, MODIFY_DATE, (SELECT A.CODE_NAME FROM CMS_CODE A WHERE A.GROUP_ID = 'C0014' AND A.CODE_ID = CMS_TRAINING_TERMS.TERMS_TYPE) AS TERMS_TYPE_NAME FROM CMS_TRAINING_TERMS WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = #{homepage_id}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY TERMS_IDX ASC

SELECT COUNT(*) FROM CMS_TRAINING_TERMS WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = #{homepage_id}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY TERMS_IDX ASC

mapper.update:
UPDATE CMS_TRAINING_TERMS
SET
	DELETE_YN = 'Y'
WHERE
	HOMEPAGE_ID = #{homepage_id}
	AND TERMS_IDX = #{terms_idx}
